            ExitStatus::Exited(code)
        } else {
            #[cfg(unix)]
            {
                use std::os::unix::process::ExitStatusExt;
                ExitStatus::Signaled {
                    signal: status.signal().unwrap_or_default(),
                    core_dumped: status.core_dumped(),
                }
            }
            #[cfg(not(unix))]
            {
                ExitStatus::Exited(1)
            }
        }
    }
